import { z } from "zod/v4";

import type { VerifiedOidcToken } from "@cyspbot/oidc";
import type { FlyMachinePrincipal } from "./principals.ts";

const optionalStringClaim = z.string().nullable().optional();
const requiredStringClaim = z.string().min(1);

const flyMachineClaimsSchema = z.object({
  app_id: requiredStringClaim,
  app_name: requiredStringClaim,
  image: optionalStringClaim,
  image_digest: optionalStringClaim,
  image_tag: optionalStringClaim,
  machine_id: requiredStringClaim,
  machine_name: requiredStringClaim,
  machine_version: requiredStringClaim,
  org_id: requiredStringClaim,
  org_name: requiredStringClaim,
  region: optionalStringClaim,
  sub: requiredStringClaim,
});

export type FlyMachineClaims = z.output<typeof flyMachineClaimsSchema>;

export function parseFlyMachineClaims(
  claims: VerifiedOidcToken["claims"],
): FlyMachineClaims | null {
  const parsedClaims = flyMachineClaimsSchema.safeParse(claims);

  if (!parsedClaims.success) {
    return null;
  }

  return parsedClaims.data;
}

export function deriveFlyMachinePrincipal(
  claims: FlyMachineClaims,
): FlyMachinePrincipal | null {
  if (claims.sub !== `${claims.org_name}:${claims.app_name}:${claims.machine_name}`) {
    return null;
  }

  return {
    appId: claims.app_id,
    appName: claims.app_name,
    image: claims.image ?? null,
    imageDigest: claims.image_digest ?? null,
    imageTag: claims.image_tag ?? null,
    machineId: claims.machine_id,
    machineName: claims.machine_name,
    machineVersion: claims.machine_version,
    orgId: claims.org_id,
    orgName: claims.org_name,
    rawSubject: claims.sub,
    region: claims.region ?? null,
  };
}

