import { describe, expect, it } from "vitest";

import {
  deriveFlyMachinePrincipal,
  parseFlyMachineClaims,
} from "../src/fly-machine-principal.ts";
import { flyTrustedIssuerForOrgSlug, parseConfiguredFlyOrgSlugs } from "../src/issuer.ts";

const validClaims = {
  app_id: "fly-app-id",
  app_name: "cyspbot-runner",
  image: "registry.fly.io/cyspbot-runner:deployment-01",
  image_digest: "sha256:0123456789abcdef",
  image_tag: "deployment-01",
  machine_id: "fly-machine-id",
  machine_name: "quiet-rain-1234",
  machine_version: "01KWR7P5J8EP4B0QJ0M3D4P5A6",
  org_id: "fly-org-id",
  org_name: "example-org",
  region: "syd",
  sub: "example-org:cyspbot-runner:quiet-rain-1234",
};

describe("Fly Machine OIDC principal derivation", () => {
  it("derives a Fly Machine principal from valid claims", () => {
    const claims = parseFlyMachineClaims(validClaims);
    const principal = claims === null ? null : deriveFlyMachinePrincipal(claims);

    expect(principal).toEqual({
      appId: "fly-app-id",
      appName: "cyspbot-runner",
      image: "registry.fly.io/cyspbot-runner:deployment-01",
      imageDigest: "sha256:0123456789abcdef",
      imageTag: "deployment-01",
      machineId: "fly-machine-id",
      machineName: "quiet-rain-1234",
      machineVersion: "01KWR7P5J8EP4B0QJ0M3D4P5A6",
      orgId: "fly-org-id",
      orgName: "example-org",
      rawSubject: "example-org:cyspbot-runner:quiet-rain-1234",
      region: "syd",
    });
  });

  it("rejects missing required Fly identity claims", () => {
    expect(parseFlyMachineClaims({ ...validClaims, app_id: "" })).toBeNull();
    expect(parseFlyMachineClaims({ ...validClaims, machine_id: undefined })).toBeNull();
  });

  it("rejects subjects that do not match the readable Fly identity claims", () => {
    const claims = parseFlyMachineClaims({ ...validClaims, sub: "example-org:other:machine" });

    expect(claims === null ? null : deriveFlyMachinePrincipal(claims)).toBeNull();
  });

  it("keeps optional runtime claims nullable", () => {
    const claims = parseFlyMachineClaims({
      ...validClaims,
      image: undefined,
      image_digest: null,
      image_tag: undefined,
      region: undefined,
    });
    const principal = claims === null ? null : deriveFlyMachinePrincipal(claims);

    expect(principal).toMatchObject({
      image: null,
      imageDigest: null,
      imageTag: null,
      region: null,
    });
  });
});

describe("Fly OIDC issuer configuration", () => {
  it("builds the trusted issuer for a configured Fly org slug", () => {
    expect(flyTrustedIssuerForOrgSlug("example-org")).toEqual({
      allowedSigningAlgorithms: ["RS256"],
      issuer: "https://oidc.fly.io/example-org",
      jwksUri: new URL("https://oidc.fly.io/example-org/.well-known/jwks"),
    });
  });

  it("rejects configured values that are not bare Fly org slugs", () => {
    expect(flyTrustedIssuerForOrgSlug("https://oidc.fly.io/example-org")).toBeNull();
    expect(flyTrustedIssuerForOrgSlug("../example-org")).toBeNull();
    expect(flyTrustedIssuerForOrgSlug("example-org?x=1")).toBeNull();
    expect(flyTrustedIssuerForOrgSlug("ExampleOrg")).toBeNull();
  });

  it("parses and normalizes configured Fly org slugs", () => {
    expect(parseConfiguredFlyOrgSlugs("example-org, other-org, example-org")).toEqual([
      "example-org",
      "other-org",
    ]);
    expect(parseConfiguredFlyOrgSlugs("")).toBeNull();
    expect(parseConfiguredFlyOrgSlugs("example-org, https://oidc.fly.io/evil")).toBeNull();
  });
});

